class Solution {
    public boolean isPrefixString(String s, String[] words) {
        StringBuilder prefix = new StringBuilder();
        for (String word : words) {
            prefix.append(word);
            if (prefix.toString().equals(s) || !s.startsWith(prefix.toString())) {
                return prefix.toString().equals(s);
            }
        }
        return false;
    }
}
